    }

    // FreeGame 和 RespinGame 狀態下都不歸零贏分（需要累積顯示）
    // 只有一般遊戲狀態下才歸零
    if ( !this.IsFreeGame && !this.IsRespinGame )
    {
        newBottombarManager.SetWinValue( 0 );
    }
}

/**@ch 按下停止按鍵 */
private ClickStop() {
    if (tools.CheckSwitchOff(SwitchOffKeyDefine.NoQuickSpin)
        || !this.CanSpaceStop
        || !this.CanPlateStop
    ) {
        return;
    }

    if (stateManager.Current() === CommonState.SPIN) {
        if (this.SlotReels.StopTime <= 0) {
            return;
        }
        if (!newBottombarManager.IsAutoSpin) {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP);
        }
        else if (!this.m_isHardStop) {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP_IN_AUTOPLAY);
        }

        // 盤面按停
        this.SlotReels.ClickStopBtn();
    }
    else if (stateManager.Current() === Game_Define.GameState.AWARD) {
        //大獎跳過
        if (newBottombarManager.IsAutoSpin) {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP);
        }
        else {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP);
        }
        this.BigWin?.Stop();
    }
}

/**@ch 處理從伺服器接收到的轉輪結果 */
OnRecvSpinAck( ack, isUnshow = false )
{
    error( "SpinAck before :", ack );

    let info = RecoverSpinAck.getInstance().RecoverSpinAck( ack );
    console.error( "SpinAck :", info );
    this.SpinAck = info;

    // 必須在 CleanInfo() 之前拍照，否則 m_bonusType 會被清成 null，BuyBonus 分支將永遠不命中
    this.UpdateFakeReelBetMode();

    // 觸發預中動畫（若有），並標記此 index 已由 OnRecvSpinAck 處理
    // SetNowRoundInfo / SetPlateInfo / SetReelTimes 延後至 SpinState 的
    // CheckPreWinEffect 完成後才呼叫，確保宣告播完再設定停輪資料
    const nowRound = this.SpinAck.RoundQueue[ 0 ];
    this.PreWinHandledIndex = 0;
    if ( nowRound.MysteryEventKind > 0 )
    {
        this.PreWinAnimPromise = new Promise<void>( ( resolve ) =>
        {
            eventManager.Dispatch(
                PRE_WIN_EVENT.PLAY_PRE_WIN_ANIM,
                nowRound.MysteryEventKind === 1 ? PreWinType.Scatter : PreWinType.Collect,
                resolve
            );
        } );
    }
    else
    {
        this.PreWinAnimPromise = Promise.resolve();
    }

    if ( this.SpinAck.RoundQueue.length > 1 )
    {
        if ( !isUnshow || this.CurPlateIndex === 0 )
        {
            // 檢查第一輪是否為FreeGame 或 RespinGame
            const firstRound = this.SpinAck.RoundQueue[0];
            if (firstRound.NextFeverGameType > 0)
            {
                firstRound.NextFeverGameType === FeverGameType.RespinGame ? this.IsGoingToRespinGame = true : this.IsGoingToFree = true;
            }
        }
    }

    this.BuyBonus?.CleanInfo();

    // 地Bar按鈕狀態
    if ( newBottombarManager.IsAutoSpin && !this.IsHardStop )
    {
        newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
    }

    // ClickStopBtn（快停）已移至 SpinState.OnEnter 的 SetNowRoundInfo 之後，
    // 確保 SetReelTimes 先執行再計算快停時間
    if ( this.IsHardStop )
    {
        newBottombarManager.SetSpinWithSpeed();
    }
    else
    {
        if ( !newBottombarManager.IsAutoSpin )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
        }
    }
}

/**@ch 設定當局盤面資訊 */
SetNowRoundInfo( round: protocol.ar2es2Proto.IRoundInfo )
{
    this.RoundInfo = round;

    if ( !this.IsFreeGame && !this.IsRespinGame )
    {
        // 檢查是否要進入FreeGame或RespinGame
        if ( round.NextFeverGameType === FeverGameType.FreeGame )
        {
            this.IsGoingToFree = true;
        }
        else if ( round.NextFeverGameType === FeverGameType.RespinGame )
        {
            this.IsGoingToRespinGame = true;
        }
    }

    if ( this.IsFreeGame && this.CurPlateIndex < this.SpinAck.RoundQueue.length - 1)
    {
        const nowRound = this.SpinAck.RoundQueue[this.CurPlateIndex];
        if (nowRound.NextFeverGameType === FeverGameType.RespinInFreeGame)
        {
            this.IsGoingToRespinGame = true;
        }
    }

    const plateSymbol = this.RoundInfo?.PlateQueue?.[0]?.PlateSymbol ?? [];
    this.m_slotReels.SetPlateInfo( RecoverSpinAck.getInstance().ConvertPlate( plateSymbol ) );
}

/**@ch spin前清理狀態 */
ClearAll()
{
    if ( !this.IsFreeGame )
    {
        this.m_effectPlate.ReturnAll();
    }

    this.m_slotReels.ShowPlate();
    this.SlotReels.SetSymbolDark( false, -1 );

    this.m_isManualHardStop = false;
}

//#region Symbol相關
/**@ch 取得symbol的spriteFrame */
GetSymbolSpriteFrame(symbol: number): SpriteFrame {
    return this.m_symbolSpriteFrames[symbol];
}

/**
 * @ch 取得 Symbol 模糊圖（無對應模糊圖時 fallback 至一般圖）
 * @param symbol Symbol ID
 */
GetBlurSymbolSpriteFrame(symbol: number): SpriteFrame {
    return this.m_blurSymbolSpriteFrames.get(symbol) ?? this.m_symbolSpriteFrames[symbol];
}

/**
 * @ch 查詢是否有對應的模糊圖
 * @param symbol Symbol ID
 */
HasBlurSymbolSpriteFrame(symbol: number): boolean {
    return this.m_blurSymbolSpriteFrames.has(symbol);
}

/**
 * @ch 取得暗色 Symbol 圖（無對應暗色圖時 fallback 至一般圖）
 * @param symbol Symbol ID
 */
GetDarkSymbolSpriteFrame(symbol: number): SpriteFrame {
    return this.m_darkSymbolSpriteFrames.get(symbol) ?? this.m_symbolSpriteFrames[symbol];
}

/**
 * @ch 取得 Jackpot 圖
