    return this.m_isFreeGameFirstSpinContinuous;
}
public set IsFreeGameFirstSpinContinuous(v: boolean) {
    this.m_isFreeGameFirstSpinContinuous = v;
}

/**@ch 要進FG之旗標 */
private m_isGoingToFree: boolean = false;
public get IsGoingToFree() {
    return this.m_isGoingToFree;
}
public set IsGoingToFree(v: boolean) {
    this.m_isGoingToFree = v;
}

/**@ch 現在在RespinGame中 */
private m_isRespinGame: boolean = false;
public get IsRespinGame(): boolean {
    return this.m_isRespinGame;
}
