    return this.m_isGoingToRespinGame;
}
public set IsGoingToRespinGame(v: boolean) {
    this.m_isGoingToRespinGame = v;
}

/**@ch 當局贏分 */
private m_win: number = 0;
public get Win() {
    return this.m_win;
}
public set Win(v: number) {
    this.m_win = v;
}

