import { _decorator } from "cc";
import protocol from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto/ar2es2Proto.js";
import { tools } from "db://astarte-framework/utilis";

const { ccclass } = _decorator;
@ccclass( "RecoverSpinAck" )
export class RecoverSpinAck
{
    private static _instance: RecoverSpinAck | null = null;

    constructor()
    {
        if ( RecoverSpinAck._instance )
        {
            throw new Error( "Error: Instantiation failed: Use RecoverSpinAck.getInstance() instead of new." );
        }
        RecoverSpinAck._instance = this;
    }

    public static getInstance(): RecoverSpinAck
    {
        if ( !this._instance )
        {
            this._instance = new RecoverSpinAck();
        }
        return this._instance;
    }

    /**@ch 收到protocol的資料，要做復原 */
    RecoverSpinAck( ack: protocol.ar2es2Proto.ISpinAck )
    {
        let ret = new protocol.ar2es2Proto.SpinAck();
        ret.RoundQueue = this.TraverseRoundQueue( ack.RoundQueue );
        ret.FreeTotalWin = ack.FreeTotalWin || 0;
        ret.TotalWin = ack.TotalWin || 0;
        ret.Bet = ack.Bet || 0;
        ret.ScAccuStage = ack.ScAccuStage || 0;
        ret.ScAccuCount = ack.ScAccuCount || 0;
        ret.BetType = ack.BetType || 0;
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param RoundQueue 原始資料
     * @returns 轉換後的資料
     */
    TraverseRoundQueue( RoundQueue: protocol.ar2es2Proto.IRoundInfo[] ) : protocol.ar2es2Proto.RoundInfo[]
    {
        let roundQueue: protocol.ar2es2Proto.RoundInfo[] = [];
        for ( let i = 0; i < RoundQueue.length; ++i )
        {
            let t = new protocol.ar2es2Proto.RoundInfo();
            let cur = RoundQueue[ i ];

            t.PlateQueue = this.TraversePlateQueue( cur.PlateQueue );
            t.AwardTypeFlag = cur.AwardTypeFlag || 0;
            t.RoundWin = cur.RoundWin || 0;
            t.ReelWeightResult = cur.ReelWeightResult || 0;
            t.MaxFlag = cur.MaxFlag || false;
            t.CurrFeverGameType = cur.CurrFeverGameType || 0;
            t.NextFeverGameType = cur.NextFeverGameType || 0;
            t.FreeRemainRound = cur.FreeRemainRound || 0;
            t.FreeNowRound = cur.FreeNowRound || 0;
            t.FreeTotalRound = cur.FreeTotalRound || 0;
            t.MysteryEventKind = cur.MysteryEventKind || 0;
            t.NearMissKind = cur.NearMissKind || 0;
            t.NearMissStartCol = cur.NearMissStartCol || 0;
            t.PreScAccuStage = cur.PreScAccuStage || 0;
            t.PreScAccuCount = cur.PreScAccuCount || 0;
            t.ScAccuStage = cur.ScAccuStage || 0;
            t.ScAccuCount = cur.ScAccuCount || 0;
            t.ScAccuUpgrade = cur.ScAccuUpgrade ? this.TraverseScAccuUpgradeInfo( cur.ScAccuUpgrade ) : null;
            t.FreeGameExtraSpins = cur.FreeGameExtraSpins || 0;
            t.RespinLockedPos = cur.RespinLockedPos || [];
            t.WheelFeatures = this.TraverseFeatureResults( cur.WheelFeatures );
            t.WheelCount = cur.WheelCount || 0;
            t.PreGridFeature = this.TraverseGridColumns( cur.PreGridFeature );
            t.TransferResult = this.TraverseTransformInfos( cur.TransferResult );
            t.UpgradeResult = this.TraverseTransformInfos( cur.UpgradeResult );

            roundQueue.push( t );
        }
        return roundQueue;
    }

    TraversePlateQueue( data: protocol.ar2es2Proto.IPlateInfo[] ) : protocol.ar2es2Proto.PlateInfo[]
    {
        if ( !data || !Array.isArray( data ) ) { return []; }
        return data.map( item => this.TraversePlateInfo( item ) );
    }

    TraversePlateInfo( data: protocol.ar2es2Proto.IPlateInfo ) : protocol.ar2es2Proto.PlateInfo
    {
        let ret = new protocol.ar2es2Proto.PlateInfo();
        ret.PlateSymbol = this.TraverseCColumns( data.PlateSymbol );
        ret.AwardDataVec = this.TraverseAwardDataVec( data.AwardDataVec );
        ret.Win = data.Win || 0;
        ret.FeaturePosQueue = this.TraverseFeaturePosQueue( data.FeaturePosQueue );
        return ret;
    }

    TraverseScAccuUpgradeInfo( data: protocol.ar2es2Proto.IScAccuUpgradeInfo ) : protocol.ar2es2Proto.ScAccuUpgradeInfo
    {
        let ret = new protocol.ar2es2Proto.ScAccuUpgradeInfo();
        ret.Upgrade = data.Upgrade || false;
        ret.Stage = data.Stage || 0;
        ret.Count = data.Count || 0;
        return ret;
    }

    TraverseFeatureResults( data: protocol.ar2es2Proto.IFeatureResult[] ) : protocol.ar2es2Proto.FeatureResult[]
    {
        if ( !data || !Array.isArray( data ) ) { return []; }
        return data.map( item =>
        {
            let ret = new protocol.ar2es2Proto.FeatureResult();
            ret.Type = item.Type || 0;
            ret.SlotIndex = item.SlotIndex || 0;
            ret.Count = item.Count || 0;
            ret.Positions = item.Positions || [];
            ret.Multipliers = item.Multipliers || [];
            return ret;
        } );
    }

    TraverseGridColumns( data: protocol.ar2es2Proto.IGridColumn[] ) : protocol.ar2es2Proto.GridColumn[]
    {
        if ( !data || !Array.isArray( data ) ) { return []; }
        return data.map( item =>
        {
            let ret = new protocol.ar2es2Proto.GridColumn();
            ret.Col = item.Col?.map( gi =>
            {
                let gridInfo = new protocol.ar2es2Proto.GridInfo();
                gridInfo.Mark = gi.Mark || 0;
                gridInfo.Multiplier = gi.Multiplier || 0;
                return gridInfo;
            } ) ?? [];
            return ret;
        } );
    }

    TraverseTransformInfos( data: protocol.ar2es2Proto.ITransformInfo[] ) : protocol.ar2es2Proto.TransformInfo[]
    {
        if ( !data || !Array.isArray( data ) ) { return []; }
        return data.map( item =>
        {
            let ret = new protocol.ar2es2Proto.TransformInfo();
            ret.Pos = item.Pos || 0;
            ret.Symbol = item.Symbol || 0;
            ret.JPState = item.JPState || 0;
            ret.Number = item.Number || 0;
            return ret;
        } );
    }

    TraverseFeaturePosQueue( data: protocol.ar2es2Proto.IIntAry[] ) : protocol.ar2es2Proto.IntAry[]
    {
        let ret: protocol.ar2es2Proto.IntAry[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            ret.push( this.TraverseIntAry( data[ i ] ) );
        }
        return ret;
    }

    TraverseColumns( data: protocol.ar2es2Proto.IColumn[] ) : protocol.ar2es2Proto.Column[]
    {
        if ( !data || !Array.isArray( data ) )
        {
            return [];
        }

        let ret: protocol.ar2es2Proto.Column[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            if ( !data[ i ] )
            {
                let emptyColumn = new protocol.ar2es2Proto.Column();
                emptyColumn.Col = [];
                ret.push( emptyColumn );
            }
            else
            {
                ret.push( this.TraverseColumn( data[ i ] ) );
            }
        }
        return ret;
    }

    TraverseColumn( data: protocol.ar2es2Proto.IColumn ) : protocol.ar2es2Proto.Column
    {
        let ret = new protocol.ar2es2Proto.Column();

        if ( !data )
        {
            ret.Col = [];
            return ret;
        }

        if ( !ret.Col )
        {
            ret.Col = [];
        }

        if ( !data.Col || !Array.isArray( data.Col ) )
        {
            ret.Col = [];
            return ret;
        }

        for ( let i = 0; i < data.Col.length; ++i )
        {
            let processedValue = this.EnsureNum( data.Col[ i ] );
            ret.Col.push( processedValue );
        }

        return ret;
    }

    TraverseCColumns( data: protocol.ar2es2Proto.ICColumn[] ) : protocol.ar2es2Proto.CColumn[]
    {
        if ( !data || !Array.isArray( data ) )
        {
            return [];
        }

        let ret: protocol.ar2es2Proto.CColumn[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            if ( !data[ i ] )
            {
                let emptyColumn = new protocol.ar2es2Proto.CColumn();
                emptyColumn.Col = [];
                ret.push( emptyColumn );
            }
            else
            {
                ret.push( this.TraverseCColumn( data[ i ] ) );
            }
        }
        return ret;
    }

    TraverseCColumn( data: protocol.ar2es2Proto.ICColumn ) : protocol.ar2es2Proto.CColumn
    {
        let ret = new protocol.ar2es2Proto.CColumn();
        if ( !data.Col )
        {
            return ret;
        }

        for ( let i = 0; i < data.Col.length; ++i )
        {
            ret.Col.push( this.TraverseCSymbol( data.Col[ i ] ) );
        }
        return ret;
    }

    TraverseCSymbol( data: protocol.ar2es2Proto.ICSymbol ) : protocol.ar2es2Proto.CSymbol
    {
        let ret = new protocol.ar2es2Proto.CSymbol();
        ret.Symbol = data.Symbol || 0;
        ret.JPState = data.JPState || 0;
        ret.Number = data.Number || 0;
        return ret;
    }

    TraverseAwardDataVec( data: protocol.ar2es2Proto.IAwardData[] ) : protocol.ar2es2Proto.AwardData[]
    {
        if ( !data || !Array.isArray( data ) )
        {
            return [];
        }

        let ret: protocol.ar2es2Proto.AwardData[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            if ( data[ i ] )
            {
                let t = this.TraverseAwardData( data[ i ] );
                ret.push( t );
            }
        }
        return ret;
    }

    TraverseIntegerList( data: number[] ) : number[]
    {
        if ( !data || !Array.isArray( data ) )
        {
            return [];
        }

        let ret: number[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            let t = this.EnsureNum( data[ i ] );
            ret.push( t );
        }
        return ret;
    }

    TraverseAwardData( data: protocol.ar2es2Proto.IAwardData ) : protocol.ar2es2Proto.AwardData
    {
        let ret = new protocol.ar2es2Proto.AwardData();
        ret.AwardType = this.EnsureNum( data.AwardType );
        ret.Symbol = this.EnsureNum( data.Symbol );
        ret.Count = this.EnsureNum( data.Count );
        ret.Line = this.EnsureNum( data.Line );
        ret.Win = this.EnsureNum( data.Win );
        ret.Multiplier = this.EnsureNum( data.Multiplier );
        ret.JackpotWin = this.EnsureNum( data.JackpotWin );
        return ret;
    }

    TraverseArrays( data: boolean[] )
    {
        let ret = [];
        for ( let i = 0; i < data.length; ++i )
        {
            ret[ i ] = data[ i ];
        }
        return ret;
    }

    TraverseIntAry( data: protocol.ar2es2Proto.IIntAry ) : protocol.ar2es2Proto.IntAry
    {
        let ret = new protocol.ar2es2Proto.IntAry();
        ret.Data = data.Data || [];
        return ret;
    }

    ConvertPlate( content: Array<protocol.ar2es2Proto.ICColumn> ): Array<protocol.ar2es2Proto.CColumn>
    {
        if ( !content || !Array.isArray( content ) )
        {
            return [];
        }

        let realPlate: protocol.ar2es2Proto.CColumn[] = [];
        for ( let i = 0; i < content.length; i++ )
        {
            if ( content[ i ] )
            {
                let column = new protocol.ar2es2Proto.CColumn( content[ i ] );
                realPlate.push( column );
            }
            else
            {
                let emptyColumn = new protocol.ar2es2Proto.CColumn();
                emptyColumn.Col = [];
                realPlate.push( emptyColumn );
            }
        }
        return realPlate;
    }

    EnsureNum( input: number )
    {
        return input || 0;
    }

    ConvertCColumn( data: number[] ) : protocol.ar2es2Proto.CColumn
    {
        let ret = new protocol.ar2es2Proto.CColumn();

        if ( !data || !Array.isArray( data ) )
        {
            ret.Col = [];
            return ret;
        }

        ret.Col = data.map( symbol =>
        {
            let cSymbol = new protocol.ar2es2Proto.CSymbol();
            cSymbol.Symbol = this.EnsureNum( symbol );
            cSymbol.JPState = 0;
            cSymbol.Number = 0;
            return cSymbol;
        } );

        return ret;
    }

    ConvertCColumns( data: number[][] ) : protocol.ar2es2Proto.CColumn[]
    {
        if ( !data || !Array.isArray( data ) )
        {
            return [];
        }

        let ret: protocol.ar2es2Proto.CColumn[] = [];
        for ( let i = 0; i < data.length; i++ )
        {
            ret.push( this.ConvertCColumn( data[ i ] ) );
        }
        return ret;
    }

    ConvertDemoAck( ack: protocol.ar2es2Proto.ISpinAck, targetBet: number )
    {
        if ( !ack )
            return;

        const winScale = targetBet / ack.Bet;
        if ( winScale != 1 )
        {
            ack.Bet = targetBet;
            ack.FreeTotalWin = tools.times( ack.FreeTotalWin, winScale );
            ack.TotalWin = tools.times( ack.TotalWin, winScale );
            ack.RoundQueue.forEach( roundInfo =>
            {
                roundInfo.RoundWin = tools.times( roundInfo.RoundWin, winScale );
                roundInfo.PlateQueue?.forEach( plateInfo =>
                {
                    plateInfo.AwardDataVec?.forEach( adv => { adv.Win = tools.times( adv.Win, winScale ); } );
                    plateInfo.PlateSymbol?.forEach( column => { column.Col?.forEach( symbol => { if ( symbol.Number > 0 ) symbol.Number = tools.times( symbol.Number, winScale ); } ); } );
                } );
            } );
        }
    }
}

