private SetStateMachine() {
    let states = {};
    states[CommonState.WAIT_RES] = new WaitResState(this);
    states[Game_Define.GameState.WAIT_READY] = new WaitReadyState(this);
    states[Game_Define.GameState.PLATE_SHOW] = new PlateShowState(this);
    this.m_featureShowState = new FeatureShowState(this);
    states[Game_Define.GameState.FEATURE_SHOW] = this.m_featureShowState;
    states[Game_Define.GameState.UNSHOW_PREPARE] = new UnshowPrepareState(this);
    states[CommonState.IDLE] = new IdleState(this);
    states[CommonState.SPIN] = new SpinState(this);
    states[Game_Define.GameState.AWARD] = new AwardState(this);
    states[Game_Define.GameState.ROUND_SHOW_END] = new RoundShowEndState(this);
    states[CommonState.CHECK_STATE] = new CheckState(this);
    states[Game_Define.GameState.ROUND_END] = new RoundEndState(this);
    states[Game_Define.GameState.ENTER_FREE] = new EnterFreeState(this);
    // states[ Game_Define.GameState.CHECK_JP ] = new CheckJpState( this );
    states[Game_Define.GameState.EFFECT_START] = new EffectStartState(this);
    states[Game_Define.GameState.SCATTER_SHOW] = new ScatterShowState(this);
    states[Game_Define.GameState.ADD_FREE] = new AddFreeState(this);
    states[Game_Define.GameState.FULL_REWARD] = new FullRewardState(this);
    states[Game_Define.GameState.LEAVE_FREE] = new LeaveFreeState(this);
    states[Game_Define.GameState.ENTER_RESPIN] = new EnterRespinState(this);
    states[Game_Define.GameState.LEAVE_RESPIN] = new LeaveRespinState(this);
    stateManager.Init(states);
    stateManager.NextState(CommonState.LOGIN);
}

/**@ch 重試RoundEnd */
RetryRoundEnd()
{
    commonGameManager.ReqRoundEnd(
        this.CurPlateIndex + 1,
        this.CurPlateIndex >= this.SpinAck.RoundQueue.length - 1 || this.CurPlateIndex === -1
    );
}

/**@ch 決定End State的去向 */
ForEndToNext()
{
    if ( this.IsFreeGame )
    {
        if ( this.IsFirstRound )
        {
            this.IsFirstRound = false;
            stateManager.NextState( CommonState.IDLE );
        }
        else
        {
            stateManager.NextState( CommonState.SPIN );
        }
    }
    else if ( this.IsRespinGame )
    {
        stateManager.NextState( CommonState.SPIN );
    }
    else
    {
        stateManager.NextState( CommonState.END );
    }
}

/**@ch AwardState結束後，看要往哪裡去=>只去ROUND SHOW END */
async AfterShowWin()
{
    stateManager.NextState( Game_Define.GameState.ROUND_SHOW_END );
}
//#endregion 狀態機

//#region ConnectionManager需實作 OnCommand、GetSpinInfo、CancelSpin
/**@ch 收到伺服器訊息 */
OnCommand(type: number, data: Uint8Array) {
    log("OnCommand", type);
    switch (type) {
        case Define.AckType.info: {
                log("OnCommand Define.AckType.info");

                let info: protocol.ar2es2Proto.IGameInfoData = protocol.ar2es2Proto.GameInfoData.decode( data );

                this.GoldBlitzRouletteWheelData = info.WheelData;

                this.SetTxt();
                this.SettingBottomBar();

                /**@ch 初始化JP*/
                eventManager.Dispatch( JP_EVENT.INIT, info.JPOdds );

                /**@ch 初始化魔法罐*/
                eventManager.Dispatch( MAGIC_POT_EVENT.INIT, this, info.ScAccuStage );

                /**@ch 初始化倍率*/

