TraverseRoundQueue( RoundQueue: protocol.ar2es2Proto.IRoundInfo[] ) : protocol.ar2es2Proto.RoundInfo[]
{
    let roundQueue: protocol.ar2es2Proto.RoundInfo[] = [];
    for ( let i = 0; i < RoundQueue.length; ++i )
    {
        let t = new protocol.ar2es2Proto.RoundInfo();
        let cur = RoundQueue[ i ];

        t.PlateQueue = this.TraversePlateQueue( cur.PlateQueue );
        t.AwardTypeFlag = cur.AwardTypeFlag || 0;
        t.RoundWin = cur.RoundWin || 0;
        t.ReelWeightResult = cur.ReelWeightResult || 0;
        t.MaxFlag = cur.MaxFlag || false;
        t.CurrFeverGameType = cur.CurrFeverGameType || 0;
        t.NextFeverGameType = cur.NextFeverGameType || 0;
        t.FreeRemainRound = cur.FreeRemainRound || 0;
        t.FreeNowRound = cur.FreeNowRound || 0;
        t.FreeTotalRound = cur.FreeTotalRound || 0;
        t.MysteryEventKind = cur.MysteryEventKind || 0;
        t.NearMissKind = cur.NearMissKind || 0;
        t.NearMissStartCol = cur.NearMissStartCol || 0;
        t.PreScAccuStage = cur.PreScAccuStage || 0;
        t.PreScAccuCount = cur.PreScAccuCount || 0;
        t.ScAccuStage = cur.ScAccuStage || 0;
        t.ScAccuCount = cur.ScAccuCount || 0;
        t.ScAccuUpgrade = cur.ScAccuUpgrade ? this.TraverseScAccuUpgradeInfo( cur.ScAccuUpgrade ) : null;
        t.FreeGameExtraSpins = cur.FreeGameExtraSpins || 0;
        t.WheelFeatures = this.TraverseFeatureResults( cur.WheelFeatures );
        t.WheelCount = cur.WheelCount || 0;
        t.PreGridFeature = this.TraverseGridColumns( cur.PreGridFeature );
        t.TransferResult = this.TraverseTransformInfos( cur.TransferResult );
        t.UpgradeResult = this.TraverseTransformInfos( cur.UpgradeResult );

        roundQueue.push( t );
    }
    return roundQueue;
}

TraversePlateQueue( data: protocol.ar2es2Proto.IPlateInfo[] ) : protocol.ar2es2Proto.PlateInfo[]
{
    if ( !data || !Array.isArray( data ) ) { return []; }
    return data.map( item => this.TraversePlateInfo( item ) );
}

TraversePlateInfo( data: protocol.ar2es2Proto.IPlateInfo ) : protocol.ar2es2Proto.PlateInfo
{
    let ret = new protocol.ar2es2Proto.PlateInfo();
    ret.PlateSymbol = this.TraverseCColumns( data.PlateSymbol );
    ret.AwardDataVec = this.TraverseAwardDataVec( data.AwardDataVec );
    ret.Win = data.Win || 0;
    ret.FeaturePosQueue = this.TraverseFeaturePosQueue( data.FeaturePosQueue );
    ret.RespinLockedPos = data.RespinLockedPos || [];
    return ret;
}

