/**@ch 目前盤面索引（局索引，索引 RoundQueue）
 * 註：public setter 暫保留（5 寫入點改走 AdvancePlateCursor/ResetPlateCursor/SetUnshowPlateCursor 後
 *     呼叫者歸零，待後續小任務 grep=0 再刪 setter）。 */
private m_curPlateIndex: number = -1;
public get CurPlateIndex(): Readonly<number> {
    return this.m_curPlateIndex;
}
public set CurPlateIndex(v: number) {
    this.m_curPlateIndex = v;
}

/**@ch 局內 plate 索引（索引當前 RoundInfo 的 PlateQueue；Respin 連鎖時逐手推進）。
 * 無 public setter——寫入僅經 AdvancePlateCursor / ResetPlateCursor / SetUnshowPlateCursor（BC-9）。 */
private m_curSubPlateIndex: number = 0;
public get CurSubPlateIndex(): Readonly<number> {
    return this.m_curSubPlateIndex;
}

/**@ch Respin 累積鎖定位置集合（key=serverPos）。
 * 生命週期：EnterRespinState 逐手 MergeRespinLocks 累加、LeaveRespinState ClearRespinLocks 清、
 *           ResetPlateCursor 兜底清。SlotReels 透過 RespinLockedSet 唯讀消費（與演出同源）。 */
private m_respinLockedSet: Map<number, LockedEntry> = new Map();
public get RespinLockedSet(): ReadonlyMap<number, LockedEntry> {
    return this.m_respinLockedSet;
}

/**@ch 雙層游標推進（唯一推進點）：當前局還有未播 plate → 推 sub；否則推局索引、sub 歸 0。
 * 取當前局 PlateQueue.length 傳入純函式；局索引無效（-1）時取不到 → 0 → 換局進第一局。 */
public AdvancePlateCursor(): void {
    const plateCount = this.m_spinAck?.RoundQueue?.[ this.m_curPlateIndex ]?.PlateQueue?.length ?? 0;
    const next = AdvancePlateCursorPure( this.m_curPlateIndex, this.m_curSubPlateIndex, plateCount );
    this.m_curPlateIndex = next.round;
    this.m_curSubPlateIndex = next.sub;
}

/**@ch 重置游標（idle / round 結束兜底）：局索引 -1、sub 0、清空鎖定集合。 */
public ResetPlateCursor(): void {
    this.m_curPlateIndex = -1;
    this.m_curSubPlateIndex = 0;
    this.m_respinLockedSet.clear();
}

/**@ch 設定 unshow 起點游標：指定局、sub 自 0 起（符合「Respin 斷線從該局 plate 0 重播」）。 */
public SetUnshowPlateCursor( round: number ): void {
    this.m_curPlateIndex = round;
    this.m_curSubPlateIndex = 0;
}

/**@ch 累加本手 Respin 鎖定位置（增量，server PlateInfo.RespinLockedPos 解碼後的 entries）。 */
public MergeRespinLocks( entries: ReadonlyArray<LockedEntry> ): void {
    entries.forEach( e => this.m_respinLockedSet.set( e.serverPos, e ) );
}

/**@ch 清空 Respin 鎖定集合（LeaveRespinState 離場時）。 */
public ClearRespinLocks(): void {
    this.m_respinLockedSet.clear();
}

