import { error, log } from "cc";
import { newBottombarManager, BaseState, commonGameManager, SlotBottomBarState, stateManager, eventManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { roundController } from "db://astarte-framework/utilis";
import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
import { REEL_UI_EVENT } from "../ReelUIManager";
import { PRE_WIN_EVENT, PreWinType } from "../PreWin/PreWinManager";
import { WaitUntil } from "../Common/AsyncUtils";

export class SpinState extends BaseState
{
    private m_gameView: GameView = null;

    private m_isPreWinEffectPlayed: boolean = false;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State : SPIN" );

        roundController.StartSpin();

        // 清理重複秀每條線
        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
        this.m_gameView.EffectPlate.StopOneLineShow();

        // spin前清理狀態
        this.m_gameView.ClearAll();

        // 清除轉輪UI效果
        this.ClearReelUIEffect();

        // 在 OnRecvSpinAck 前記錄版本，用於 CheckPreWinEffect 判斷本局 SpinAck 是否已到
        const prevSpinAckVersion = this.m_gameView.SpinAckVersion;

        // BC-7：EnterFreeState 表演結束直接接 FG 第一手的連續轉動旗標，讀完即清
        // 註：原本此處有 await Define.Wait(0.5) 等 FlyManager 晚到 callback 完成，
        //   現由 EnterFreeState dispatch FLY_EVENT.CANCEL_ADD_CASH_ANIMATION 直接取消晚到 callback，不需等待
        const continueSpin = this.m_gameView.IsFreeGameFirstSpinContinuous;
        if ( continueSpin )
        {
            this.m_gameView.IsFreeGameFirstSpinContinuous = false;
        }

        if ( commonGameManager.HasUnshow )
        {
            commonGameManager.HasUnshow = false;
            this.m_gameView.IsHardStop = newBottombarManager.IsHardStop;

            this.m_gameView.StartSpin( undefined, continueSpin );
            this.m_gameView.OnRecvSpinAck( this.m_gameView.UnshowSpinAck, true );
            this.m_gameView.UnshowSpinAck = null;
        }
        else
        {
            this.m_gameView.CurPlateIndex = this.m_gameView.CurPlateIndex + 1;
            // 重置標記，避免上一局殘留的 PreWinHandledIndex 誤觸 IF 分支
            this.m_gameView.PreWinHandledIndex = -1;
            this.m_gameView.StartSpin( undefined, continueSpin );
        }

        await this.CheckPreWinEffect( prevSpinAckVersion );

        // 宣告動畫完成後，統一設定盤面資料（含 SetPlateInfo → SetReelTimes）
        const nowRound = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurPlateIndex ];
        this.m_gameView.SetNowRoundInfo( nowRound );

        // SetReelTimes 已執行，可安全呼叫快停
        if ( this.m_gameView.IsHardStop && !this.m_gameView.IsMgOmen )
        {
            this.m_gameView.SlotReels.ClickStopBtn();
        }

        // FreeGame 專屬 UI 更新
        if ( this.m_gameView.IsFreeGame )
        {
            eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.SET_NOW_ROUND, nowRound.FreeNowRound );

            if ( !this.m_gameView.IsHardStop && !newBottombarManager.IsAutoSpin )
            {
                newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
            }
        }
    }

    public OnProcess( dt: number )
    {
        this.m_gameView.SlotReels.Spin( dt );
        if ( !this.m_gameView.SlotReels.IsStop || this.m_isPreWinEffectPlayed || !this.m_gameView.SlotReels.IsEntryEffectDone )
        {
            return;
        }

        this.m_gameView.CanPlateStop = true;
        this.m_gameView.CanSpaceStop = true;
        if ( !newBottombarManager.IsAutoSpin )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
        }

        stateManager.NextState( Game_Define.GameState.EFFECT_START );
    }

    public OnLeave()
    {

    }

    /**
     * @ch 播放預中效果動畫
     * @param mysteryEventKind 預中類型
     * @returns Promise 震動效果完成的 Promise
     */
    private async PlayPreWinEffect(mysteryEventKind: number): Promise<void> {
        return new Promise<void>((resolve) => {
            eventManager.Dispatch(PRE_WIN_EVENT.PLAY_PRE_WIN_ANIM, mysteryEventKind === 1 ? PreWinType.Scatter : PreWinType.Collect, resolve);
        });
    }

    /**
     * @ch 檢查預中效果動畫
     * @param prevSpinAckVersion OnEnter 開始前記錄的 SpinAckVersion，用於 Base Game 判斷新的 SpinAck 是否已到
     * @returns Promise 預中效果完成的 Promise
     */
    private async CheckPreWinEffect( prevSpinAckVersion: number ): Promise<void> {
        this.m_isPreWinEffectPlayed = true;
        const currentIndex = this.m_gameView.CurPlateIndex;

        if ( this.m_gameView.PreWinHandledIndex === currentIndex )
        {
            // OnRecvSpinAck 已為此 index 觸發動畫（Base Game 正常流程 / Unshow）
            // 直接等待該動畫結束即可
            await this.m_gameView.PreWinAnimPromise;
        }
        else if ( !this.m_gameView.IsFreeGame && !this.m_gameView.IsRespinGame )
        {
            // Base Game：OnRecvSpinAck 尚未到達，等待本局新的 SpinAck
            // 用版本號判斷，避免誤讀上一局的舊 SpinAck
            await WaitUntil( () => this.m_gameView.SpinAckVersion > prevSpinAckVersion );
            // OnRecvSpinAck 已設定 PreWinAnimPromise（有宣告時為動畫 Promise，否則為立即 resolve）
            await this.m_gameView.PreWinAnimPromise;
        }
        else
        {
            // FG / Respin 後續回合：SpinAck 資料已在首輪一次性到達，直接讀取
            if ( currentIndex < 0 )
            {
                error( "currentIndex is less than 0" );
            }
            const nowRound = this.m_gameView.SpinAck?.RoundQueue?.[ currentIndex ];
            if ( nowRound && nowRound.MysteryEventKind > 0 )
            {
                await this.PlayPreWinEffect( nowRound.MysteryEventKind );
            }
        }

        this.m_isPreWinEffectPlayed = false;
    }

    /**
     * @ch 清除轉輪UI效果
     */
    private ClearReelUIEffect()
    {
        if (!this.m_gameView.IsRespinGame)
        {
            eventManager.Dispatch(REEL_UI_EVENT.HIDE_LIGHT_LEFT_REEL);
            eventManager.Dispatch(REEL_UI_EVENT.HIDE_LIGHT_RIGHT_REEL);
        }
        eventManager.Dispatch(REEL_UI_EVENT.PREWIN_FRAME_FADE_OUT, -1);
    }
}

