/**
 * @ch fail-loud 一致性斷言：累積鎖定集合 keys 應等於該局所有 plate 的 RespinLockedPos 聯集。
 * 增量語意下最後一手 RespinLockedPos 預期為空（不再切下一手），故聯集 = 累積集合。
 * 不一致僅 console.error（不改控制流——P-3/P-5 為協議前提，偏離要看得見而非炸狀態機）。
 */
private AssertLockedConsistency(): void
{
    const expected = new Set<number>();
    this.m_gameView.RoundInfo?.PlateQueue?.forEach( plate => {
        plate?.RespinLockedPos?.forEach( pos => expected.add( pos ) );
    } );

    const actual = this.m_gameView.RespinLockedSet;
    let mismatch = actual.size !== expected.size;
    if ( !mismatch )
    {
        for ( const key of actual.keys() )
        {
            if ( !expected.has( key ) ) { mismatch = true; break; }
        }
    }
    if ( mismatch )
    {
        console.error( `[LeaveRespinState] 鎖定集合與 server RespinLockedPos 聯集不一致：`
            + `累積=[${Array.from( actual.keys() )}] vs server聯集=[${Array.from( expected )}]` );
    }
}

