import { log } from "cc";
import { BaseState, SlotBottomBarState, commonGameManager, eventManager, newBottombarManager, newExtraManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import { roundController, tempoSetting, tools } from "db://astarte-framework/utilis";
import { MULTIPLIER_EVENT } from "../Multiplier/MultiplierManager";

export class RoundEndState extends BaseState
{
    private m_gameView: GameView = null;
    private m_processTick: number = 0;
    private m_isChecking: boolean = false;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter state : ROUND_END" );

        const isNoWin = this.m_gameView.RoundInfo.RoundWin === 0;

        // 不是FG和RespinGame的話要歸零
        if ( !this.m_gameView.IsFreeGame && !this.m_gameView.IsGoingToFree && !this.m_gameView.IsRespinGame )
        {
            // 記得 歸0
            this.m_gameView.Win = 0;

            // 盤面Index回復
            this.m_gameView.CurPlateIndex = -1;

            if ( newExtraManager.IsFeaturesDemoMode )
            {
                this.m_gameView.EffectPlate.StopOneLineShow();
                newExtraManager.CheckBuyBonusOverAni();
                this.m_gameView.ClearAll();
            }

            // 重置倍數到初始值
            this.ResetMultiplierToBase();
        }

        this.m_isChecking = true;
        await this.CheckAndPlayActivateEffectEnd();

        this.m_gameView.CanSpaceStop = true;
        this.m_gameView.CanPlateStop = true;

        if (this.m_gameView.SkipFreeGameNoWinDelay) {
            // BC-3：EnterFreeState 表演結束直接進 FG 第一手，跳過 0.5s noWin 緩衝（讀完即清）
            this.m_processTick = 0;
            this.m_gameView.SkipFreeGameNoWinDelay = false;
        }
        else if (!this.m_gameView.IsFirstRound && this.m_gameView.IsFreeGame && isNoWin) {
            this.m_processTick = 0.5;
        }
        else {
            if (newBottombarManager.IsAutoSpin) {
                // 轉輪節奏模組：三幣瑞龍
                this.m_processTick = tempoSetting.TempoSetting.TripleCoinTreasure.AUTO_DELAY_TIME;
            }
            else {
                this.m_processTick = 0;
            }
        }

        this.m_gameView.RetryRoundEnd();

        this.m_isChecking = false;
    }

    public OnProcess( dt: number )
    {
        if (this.m_isChecking) {
            return;
        }

        // BC-3：EnterFreeState 表演結束 → RoundEndState → FG 第一手 SpinState 路徑期間，
        // 轉輪仍在轉動，補推進 Spin(dt) 消除視覺停頓（BC-1 視覺連續的實現手段）。
        // BC-2：其他 RoundEnd 路徑（BG 結算 / FG 後續手 / Respin 結算）IsFreeGame=false 或 IsStop=true，條件不成立、行為與原本一致。
        if ( this.m_gameView.IsFreeGame && !this.m_gameView.SlotReels.IsStop )
        {
            this.m_gameView.SlotReels.Spin( dt );
        }

        this.m_processTick = tools.strip( this.m_processTick - dt );
        if ( this.m_processTick > 0
            || !roundController.CanToNextRound()
            || ( commonGameManager.IsTwice && !commonGameManager.IsGetRoundEndAck ) )
        {
            return;
        }

        // 離開特色，要將自動玩關閉
        if ( newExtraManager.IsFeaturesDemoMode && !newBottombarManager.IsAutoSpin )
        {
            newBottombarManager.ShowAutoPlayState( false );
            this.m_gameView.EffectPlate.CurAwardLines.length = 0;
        }

        // 確認有無自動玩次數 要改變地bar顯示
        if ( newBottombarManager.IsAutoSpin && newBottombarManager.IsAutoPlayByTimes() )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_STOP_IN_AUTOPLAY );
        }

        this.m_gameView.ForEndToNext();
    }

    public OnLeave()
    {

    }

    /**
     * @ch 重置倍數到初始值
     */
    private ResetMultiplierToBase(): void
    {
        const spinAck = this.m_gameView.SpinAck;
        eventManager.Dispatch( MULTIPLIER_EVENT.SET_INDEX, spinAck.MultiplierIndex, true, true );
        log( `Reset multiplier to base: ${spinAck.MultiplierIndex}` );
    }

    /**
     * @ch 檢查發動動畫是否正在播放，如果正在播放則播放結束動畫
     */
    private async CheckAndPlayActivateEffectEnd(): Promise<void>
    {
        return new Promise<void>( (resolve) => {
            eventManager.Dispatch( MULTIPLIER_EVENT.GET_IS_ACTIVATE_EFFECT_PLAYING, (isPlaying: boolean) => {
                if (isPlaying) {
                    eventManager.Dispatch( MULTIPLIER_EVENT.PLAY_ACTIVATE_EFFECT_END );
                }
                resolve();
            });
        });
    }
}

