public SuppressInAnimationForRespinLockedPos(): void
{
    const curRound = this.m_gameView.SpinAck?.RoundQueue?.[ this.m_gameView.CurPlateIndex ];
    if ( !curRound?.RespinLockedPos?.length ) return;

    const plateSymbol = curRound.PlateQueue?.[0]?.PlateSymbol ?? [];

    curRound.RespinLockedPos.forEach( ( serverPos: number ) =>
    {
        const decoded = Common.DecodeServerPosByRowConfig( serverPos );
        if ( !decoded ) return;

        const { col, row } = decoded;
        const symbol = plateSymbol?.[ col ]?.Col?.[ row ]?.Symbol ?? -1;

        if ( symbol === Game_Define.Symbol.Cash )
        {
            this.m_cashInPlayed[ col ][ row ] = true;
        }
        else if ( symbol === Game_Define.Symbol.Mystery )
        {
            this.m_mysteryInPlayed[ col ][ row ] = true;
        }

    } );
}

