/**
 * 執行飛入 Collect Symbol 的演出
 * 包含 MysteryCash 旋轉和所有 Cash 符號的順序飛行動畫
 */
private async PlayCollectSymbolShow(): Promise<void>
{
    try {

        this.m_gameView.ClearShowSymbolInfos();
         // 先處理 awardDataVec 的資料，排除 Symbol ID 0 的
        const currentPlateInfo = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurPlateIndex ]?.PlateQueue?.[0];
        const awardDataVec = currentPlateInfo?.AwardDataVec ?? [];
        const awardSymbolInfos: ShowSymbolInfo[] = [];

        if (Array.isArray(awardDataVec) && awardDataVec.length > 0)
        {
            const mainPlateSymbol = currentPlateInfo?.PlateSymbol ?? [];

            // 處理 awardDataVec 中的每個資料
            awardDataVec.forEach(awardData => {
                if (awardData.AwardType === 0) return;

                if (awardData.AwardType === 1) {
                    this.ProcessAwardType1(awardData, mainPlateSymbol, awardSymbolInfos);
                }
                else if (awardData.AwardType === 2) {
                    this.ProcessAwardType2(mainPlateSymbol, awardSymbolInfos);
                }
            });

             // 將相同的 Symbol 分組到同一個陣列中
            const groupedSymbolInfos = this.GroupSymbolInfosBySymbol(awardSymbolInfos);
             // 設定處理好的資料到 ShowSymbolInfos
            this.m_gameView.ShowSymbolInfos = groupedSymbolInfos;
        }

        if (this.m_gameView.IsGoingToRespinGame)
            return;

        const featurePosQueue = Common.ParseFeaturePosQueue( this.m_gameView.RoundInfo?.PlateQueue?.[0]?.FeaturePosQueue ?? [] );
        // 判斷 featurePosQueue 當中是否有包含指定的 type
        const featureCollectData = featurePosQueue.find(item => item.type === FeaturePosQueueType.Collect) || null;
        const featureCashData = featurePosQueue.find(item => item.type === FeaturePosQueueType.Cash) || null;
        const featureMysteryCashData = featurePosQueue.find(item => item.type === FeaturePosQueueType.MysteryCash) || null;

