import { BaseState, eventManager, newBottombarManager, SlotBottomBarState } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define, { WinType } from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";

export class AwardState extends BaseState
{
    private m_gameView: GameView = null;

    private m_isShowAwardEffectEnd: boolean = false;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        console.log( "OnEnter State : AWARD" );

        this.m_isShowAwardEffectEnd = false;

        // ScatterShowState 演出已結束，清理板面上所有殘留 spine（保留 Collect）
        this.CleanNonCollectSpines();

        this.m_gameView.SlotReels.SetSymbolDark( false, -1 );
        let thisRoundWin: number = this.m_gameView.RoundInfo.RoundWin;
        let bet: number = Game_Define.GetNowBetValue();
        let rate = thisRoundWin / bet;

        // 有贏分
        if (rate > 0) {
            const winType = Game_Define.GetWinType(rate);

            if (this.m_gameView.IsRespinGame) {
                await this.HandleRespinGameAward(thisRoundWin, rate, winType);
            }
            else if (this.m_gameView.IsFreeGame) {
                await this.HandleFreeGameAward(thisRoundWin, rate, winType);
            }
            else {
                await this.HandleNormalGameAward(thisRoundWin, rate, winType);
            }
        }

        this.m_isShowAwardEffectEnd = true;
    }

    public OnProcess()
    {
        if (
             this.m_gameView.BigWin.IsEnd
             && ( !this.m_gameView.SlotReels.IsPlayingEffect || this.m_gameView.SpinAck.RoundQueue.length === 1 )
             && this.m_isShowAwardEffectEnd
        )
        {
            this.m_gameView.AfterShowWin();
        }
    }

    public OnLeave()
    {

    }

    /**
     * @ch 處理 RespinGame 狀態下的獲勝值計算
     * @param thisRoundWin 當前輪贏分
     * @param rate 倍率
     * @param winType 獲勝類型
     */
    private async HandleRespinGameAward(thisRoundWin: number, rate: number, winType: WinType): Promise<void>
    {
        // 如果沒有中獎，不顯示抱獎演出
        if (thisRoundWin <= 0 || winType === WinType.NoWin)
        {
            return;
        }

        // RespinGame 狀態下需要累積所有輪的贏分
        // 計算累積的總贏分（包括之前所有 respin 輪的贏分）
        const accumulatedWinValue = this.CalculateRespinWinValue();

        const totalWin = this.m_gameView.SpinAck?.TotalWin ?? 0;

        if (winType === WinType.NormalWin)
        {
            await Define.Wait( this.m_gameView, 0.3 );
            await this.m_gameView.EffectPlate.ShowSymbolEffect();
            // Respin 狀態下：使用累積的總贏分（會自動從之前的值累加顯示）
            newBottombarManager.SetWinValueWithRunning(accumulatedWinValue, 0.1);
            await this.m_gameView.SmallWin.SetWinLabelRunning( thisRoundWin, 0.1 );
            await Define.Wait( this.m_gameView, 0.15 );
        }
        else
        {
            this.m_gameView.BigWin.IsEnd = false;
            await Define.Wait( this.m_gameView, 0.3 );
            await this.m_gameView.EffectPlate.ShowSymbolEffect( false );
            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );
            await this.m_gameView.ShowBigWin(thisRoundWin, rate, winType);
            newBottombarManager.SetWinValueWithCheck({ maxWin: totalWin, value: accumulatedWinValue });
        }
    }

    /**
     * @ch 計算之前的 RespinGame 累積贏分（不包含當前輪）
     * @returns 之前所有 respin 輪的累積贏分
     */
    private CalculatePreviousRespinWinValue(): number
    {   
        let totalRespinWin = 0;

        // 累積所有已完成的 RespinGame 輪贏分（不包含當前輪）
        if (this.m_gameView.SpinAck && this.m_gameView.SpinAck.RoundQueue)
        {
            for (let i = 0; i < this.m_gameView.CurPlateIndex; i++)
            {
                const roundInfo = this.m_gameView.SpinAck.RoundQueue[i];
                if (roundInfo && roundInfo.RoundWin)
                {
                    totalRespinWin += roundInfo.RoundWin;
                }
            }
        }

        return totalRespinWin;
    }

    /**
     * @ch 處理一般遊戲狀態下的獲勝值計算
     * @param thisRoundWin 當前輪贏分
     * @param rate 倍率
     * @param winType 獲勝類型
     */
    private async HandleNormalGameAward(thisRoundWin: number, rate: number, winType: WinType): Promise<void>
    {
        // 如果沒有中獎，不顯示抱獎演出
        if (thisRoundWin <= 0 || winType === WinType.NoWin)
        {
            return;
        }

        if (winType === WinType.NormalWin)
        {
            await Define.Wait( this.m_gameView, 0.3 );
            await this.m_gameView.EffectPlate.ShowSymbolEffect();
            newBottombarManager.SetWinValueWithRunning(thisRoundWin, 0.1);
            await this.m_gameView.SmallWin.SetWinLabelRunning( thisRoundWin, 0.1 );
            await Define.Wait( this.m_gameView, 0.15 );
        }
        else
        {
            this.m_gameView.BigWin.IsEnd = false;
            await Define.Wait( this.m_gameView, 0.3 );
            await this.m_gameView.EffectPlate.ShowSymbolEffect( false );
            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );
            await this.m_gameView.ShowBigWin(thisRoundWin, rate, winType);
            // 使用跑分動畫方式設定贏分（等待 BigWin 動畫完成後才設定）
            newBottombarManager.SetWinValueWithRunning(thisRoundWin, 0.1);
        }
    }

    /**
     * @ch 處理 FreeGame 狀態下的獲勝值計算
     * @param thisRoundWin 當前輪贏分
     * @param rate 倍率
     * @param winType 獲勝類型
     */
    private async HandleFreeGameAward(thisRoundWin: number, rate: number, winType: WinType): Promise<void>
    {
        // 如果沒有中獎，不顯示抱獎演出
        if (thisRoundWin <= 0 || winType === WinType.NoWin)
        {
            return;
        }

        // FreeGame 狀態下需要累積所有輪的贏分
        // 計算累積的總贏分（包括之前所有 FreeGame 輪的贏分）
        const accumulatedWinValue = this.CalculateFreeGameWinValue();
        const totalWin = this.m_gameView.SpinAck?.TotalWin ?? 0;

        if (winType === WinType.NormalWin)
        {
            await Define.Wait( this.m_gameView, 0.3 );
            await this.m_gameView.EffectPlate.ShowSymbolEffect();
            // FreeGame 狀態下：使用累積的總贏分（會自動從之前的值累加顯示）
            newBottombarManager.SetWinValueWithRunning(accumulatedWinValue, 0.1);
            await this.m_gameView.SmallWin.SetWinLabelRunning( thisRoundWin, 0.1 );
            await Define.Wait( this.m_gameView, 0.15 );
        }
        else
        {
            this.m_gameView.BigWin.IsEnd = false;
            await Define.Wait( this.m_gameView, 0.3 );
            await this.m_gameView.EffectPlate.ShowSymbolEffect( false );
            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );
            await this.m_gameView.ShowBigWin(thisRoundWin, rate, winType);
            newBottombarManager.SetWinValueWithCheck({ maxWin: totalWin, value: accumulatedWinValue });
        }
    }

    /**
     * @ch 計算之前的 FreeGame 累積贏分（不包含當前輪）
     * @returns 之前所有 FreeGame 輪的累積贏分
     */
    private CalculatePreviousFreeGameWinValue(): number
    {   
        let totalFreeGameWin = 0;

        // 累積所有已完成的 FreeGame 輪贏分（不包含當前輪）
        if (this.m_gameView.SpinAck && this.m_gameView.SpinAck.RoundQueue)
        {
            for (let i = 0; i < this.m_gameView.CurPlateIndex; i++)
            {
                const roundInfo = this.m_gameView.SpinAck.RoundQueue[i];
                if (roundInfo && roundInfo.RoundWin)
                {
                    totalFreeGameWin += roundInfo.RoundWin;
                }
            }
        }

        return totalFreeGameWin;
    }

    /**
     * @ch 計算 FreeGame 的獲勝值
     * @returns FreeGame 狀態下的獲勝值
     */
    private CalculateFreeGameWinValue(): number
    {
        let totalFreeGameWin = 0;

        // 累積所有已完成的 FreeGame 輪贏分
        if (this.m_gameView.SpinAck && this.m_gameView.SpinAck.RoundQueue)
        {
            for (let i = 0; i <= this.m_gameView.CurPlateIndex; i++)
            {
                const roundInfo = this.m_gameView.SpinAck.RoundQueue[i];
                if (roundInfo && roundInfo.RoundWin)
                {
                    totalFreeGameWin += roundInfo.RoundWin;
                }
            }
        }

        return totalFreeGameWin;
    }

    /**
     * @ch 計算 RespinGame 的獲勝值
     * @returns RespinGame 狀態下的獲勝值
     */
    private CalculateRespinWinValue(): number
    {
        let totalRespinWin = 0;

        // 累積所有已完成的 RespinGame 輪贏分
        if (this.m_gameView.SpinAck && this.m_gameView.SpinAck.RoundQueue)
        {
            for (let i = 0; i <= this.m_gameView.CurPlateIndex; i++)
            {
                const roundInfo = this.m_gameView.SpinAck.RoundQueue[i];
                if (roundInfo && roundInfo.RoundWin)
                {
                    totalRespinWin += roundInfo.RoundWin;
                }
            }
        }

        return totalRespinWin;
    }

    /**@ch 清理板面上所有殘留的 layer TWO spine，Collect / CollectAndRetrigger 除外 */
    private CleanNonCollectSpines(): void
    {
        const plate = this.m_gameView.SlotReels.PlateInfo;
        for ( let col = 0; col < plate.length; col++ )
        {
            const column = plate[ col ];
            if ( !column?.Col ) continue;
            for ( let row = 0; row < column.Col.length; row++ )
            {
                const sym = column.Col[ row ]?.Symbol;
                if ( sym === Game_Define.Symbol.Collect || sym === Game_Define.Symbol.CollectAndRetrigger )
                {
                    continue;
                }
                this.m_gameView.EffectPlate.CleanSymbolSpineAt( col, row, Game_Define.LAYERS.TWO );
            }
        }
    }

    /**@ch 秀中獎表演 */
    private async ShowSymbolEffect()
    {
        await this.m_gameView.EffectPlate.ShowSymbolEffect();
    }

}

